                raise RuntimeError("JobQueue has been shut down")
            self._seq += 1
            seq = self._seq
            self._results[job_id] = {'status': 'pending'}
            self._pqueue.put(_Item(priority, seq, (job_id, fn, args)))

    def get_result(self, job_id, timeout=30):
