```python
import threading
import queue
import time

_STOP = object()


class _Item:
    # Only (priority, seq) are compared — payload is never compared.
    __slots__ = ('priority', 'seq', 'payload')

    def __init__(self, priority, seq, payload):
        self.priority = priority
        self.seq = seq
        self.payload = payload

    def __lt__(self, other): return (self.priority, self.seq) < (other.priority, other.seq)
    def __le__(self, other): return (self.priority, self.seq) <= (other.priority, other.seq)
    def __gt__(self, other): return (self.priority, self.seq) > (other.priority, other.seq)
    def __ge__(self, other): return (self.priority, self.seq) >= (other.priority, other.seq)
    def __eq__(self, other): return (self.priority, self.seq) == (other.priority, other.seq)


class JobQueue:
    def __init__(self, workers=4):
        self._pqueue = queue.PriorityQueue()
        self._condition = threading.Condition()
        self._results = {}
        self._seq = 0
        self._stopped = False
        self._workers = []
        for _ in range(workers):
            t = threading.Thread(target=self._worker, daemon=True)
            t.start()
            self._workers.append(t)

    def _worker(self):
        while True:
            try:
                item = self._pqueue.get()
            except Exception:
                with self._condition:
                    if self._stopped:
                        return
                continue

            try:
                if item.payload is _STOP:
                    return

                job_id, fn, args = item.payload

                # Atomically transition 'pending' -> 'running' under the lock.
                # If cancel() won the race first, status is already 'cancelled';
                # skip the job without running fn so cancel()'s promise holds.
                with self._condition:
                    if self._results.get(job_id, {}).get('status') != 'pending':
                        continue  # task_done() still fires in finally
                    self._results[job_id] = {'status': 'running'}

                try:
                    result = fn(*args)
                    with self._condition:
                        self._results[job_id] = {'status': 'done', 'result': result}
                        self._condition.notify_all()
                except Exception as e:
                    with self._condition:
                        self._results[job_id] = {'status': 'error', 'error': str(e)}
                        self._condition.notify_all()
            finally:
                self._pqueue.task_done()

    def submit(self, job_id, fn, *args, priority=3):
        """Queue a job. priority 1 = highest, 5 = lowest; FIFO within equal priority."""
        if not (isinstance(priority, int) and 1 <= priority <= 5):
            raise ValueError(f"priority must be an integer 1-5, got {priority!r}")
        with self._condition:
            if self._stopped:
                raise RuntimeError("JobQueue has been shut down")
            self._seq += 1
            seq = self._seq
            self._results[job_id] = {'status': 'pending'}
            self._pqueue.put(_Item(priority, seq, (job_id, fn, args)))

    def cancel(self, job_id):
        """
        Cancel a queued job.

        Returns:
          'cancelled'       — job was pending in the queue and has been cancelled
          'already_running' — a worker has already started the job
          'not_found'       — job_id unknown, already completed, or already cancelled
        """
        with self._condition:
            result = self._results.get(job_id)
            if result is None:
                return 'not_found'
            status = result['status']
            if status == 'pending':
                self._results[job_id] = {'status': 'cancelled'}
                self._condition.notify_all()  # wake any get_result() waiters
                return 'cancelled'
            if status == 'running':
                return 'already_running'
            return 'not_found'  # done, error, or already cancelled

    def get_result(self, job_id, timeout=30):
        deadline = time.monotonic() + timeout
        with self._condition:
            while True:
                result = self._results.get(job_id)
                # Wait through both 'pending' and 'running'; return on any terminal state.
                if result is not None and result['status'] not in ('pending', 'running'):
                    return result
                remaining = deadline - time.monotonic()
                if remaining <= 0:
                    return {'status': 'timeout'}
                self._condition.wait(timeout=remaining)

    def shutdown(self, wait=True):
